use bevy_app::Plugin; use bevy_ecs::prelude::*; use azalea_world::ChunkStorage; use noise::{NoiseFn, Perlin}; pub struct WorldPlugin; #[derive(Resource)] pub struct ServerWorld { pub storage: ChunkStorage, pub terrain: Perlin, } impl Plugin for WorldPlugin { fn build(&self, app: &mut bevy_app::App) { app.insert_resource(ServerWorld { storage: ChunkStorage::default(), terrain: Perlin::new(42), }); app.add_systems(bevy_app::Update, generate_chunks); } } fn generate_chunks(mut world: ResMut<ServerWorld>) { let _ = world.terrain.get([0.0, 0.0, 0.0]); }
